// Normalize Z-API payload and validate (v1.2 - fix body.body.text)
// Goals:
// - Use ONLY body.messageId as provider_message_id
// - Handle both body.text.message (Z-API real) and body.body.text (test format)
// - Keep whitelist + early exits

const input = $input.first().json;
const body = input.body || input;

// provider_message_id: DO NOT fallback to other ids
const provider_message_id = body.messageId ?? null;
if (!provider_message_id) {
  return [{ json: { _exit: 'missing_messageId', status: 'ignored_missing_messageId' } }];
}

const rawPhone = body.phone || body.from || '';
const digits = String(rawPhone).replace(/\D/g, '');

function canonicalizeBRPhone(d) {
  let x = d.replace(/^0+/, '');
  if (!x.startsWith('55') && (x.length === 10 || x.length === 11)) {
    x = '55' + x;
  }
  if (x.startsWith('55') && x.length === 12) {
    x = x.slice(0, 4) + '9' + x.slice(4);
  }
  if (x.startsWith('55') && x.length > 13) {
    x = x.slice(0, 13);
  }
  return x;
}

const from_phone = canonicalizeBRPhone(digits);

// Whitelist canonical only
const WHITELIST = ['5593984236996'];
if (!WHITELIST.includes(from_phone)) {
  return [{
    json: {
      _exit: 'unauthorized',
      status: 'ignored_unauthorized',
      from_phone_raw: digits,
      from_phone_canon: from_phone
    }
  }];
}

function normalizeToPhone(v) {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  if (!s) return null;
  const lower = s.toLowerCase();
  if (lower === 'empty' || lower === 'null' || lower === 'undefined' || lower === 'none' || lower === '-') {
    return null;
  }
  const d = s.replace(/\D/g, '');
  if (!d) return null;
  return canonicalizeBRPhone(d);
}

const to_phone = normalizeToPhone(body.to || body.toPhone);

// Determine message type + content
// Handle multiple formats:
// - Z-API real: body.text.message
// - Test format: body.body.text
// - Simple: body.text (string)
let type = 'text';
let text_raw = '';
let media_url = null;

// Try different text formats
if (body.text?.message) {
  type = 'text';
  text_raw = body.text.message;
} else if (body.body?.text) {
  // Test format: body.body.text
  type = 'text';
  text_raw = body.body.text;
} else if (typeof body.text === 'string') {
  // Simple string format
  type = 'text';
  text_raw = body.text;
} else if (body.audio) {
  type = 'audio';
  media_url = body.audio.audioUrl || null;
} else if (body.image) {
  type = 'image';
  media_url = body.image.imageUrl || null;
} else if (body.document) {
  type = 'document';
  media_url = body.document.documentUrl || null;
}

const meta = {
  zapi: {
    messageId: body.messageId ?? null,
    timestamp: body.timestamp ?? body.time ?? null,
    instanceId: body.instanceId ?? null,
  },
  from_phone,
  to_phone,
  content: {
    type,
    hasText: Boolean(text_raw),
    hasAudio: Boolean(body.audio),
    hasImage: Boolean(body.image),
    hasDocument: Boolean(body.document),
  }
};

return [{
  json: {
    _exit: null,
    provider: 'zapi',
    provider_message_id,
    from_phone,
    to_phone,
    direction: 'in',
    type,
    text_raw,
    media_url,
    meta
  }
}];

// Ensure we always have output even if Supabase returned empty
const inputItems = $input.all();
const originalData = $('TRF_NormalizeAndValidate').first().json;

// Check if we got any results from Supabase
const hasResults = inputItems.length > 0 && inputItems[0].json && inputItems[0].json.id;

if (hasResults) {
  return [{ json: { ...originalData, is_duplicate: true, existing_id: inputItems[0].json.id } }];
} else {
  return [{ json: { ...originalData, is_duplicate: false, existing_id: null } }];
}

