// Parse LLM extraction response and apply lead_time
const llmResponse = $input.first().json;
const inputData = $('TRF_BuildLLMContext').first().json;

let items = [];
let needsClarification = false;
let clarificationQuestion = '';

try {
  const content = llmResponse.choices?.[0]?.message?.content || "";
  const jsonMatch = content.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);

    if (parsed.needs_clarification) {
      needsClarification = true;
      clarificationQuestion = parsed.clarification_question || 'Preciso de mais informações.';
    } else if (parsed.items && Array.isArray(parsed.items)) {
      items = parsed.items;
    }
  }
} catch (e) {
  console.log('Parse error:', e.message);
  needsClarification = true;
  clarificationQuestion = 'Não consegui entender. Pode reformular?';
}

// Get lead_time from user_prefs (default 900 = 15min)
const leadTimeSeconds = inputData.lead_time_default_seconds || 900;

// Process each item and apply lead_time
const processedItems = items.map((item, idx) => {
  let notify_at = null;

  // For reminders with due_at, calculate notify_at
  if (item.type === 'reminder' && item.due_at) {
    const dueDate = new Date(item.due_at);
    const notifyDate = new Date(dueDate.getTime() - (leadTimeSeconds * 1000));
    notify_at = notifyDate.toISOString();
  }

  return {
    ...inputData,
    intent: item.type || 'task',
    title: item.title || 'Sem título',
    details: item.details || null,
    due_at: item.due_at || null,
    notify_at: notify_at,
    needs_clarification: false,
    is_multi_intent: items.length > 1,
    item_index: idx,
    total_items: items.length
  };
});

// If needs clarification, return single item with clarification
if (needsClarification) {
  return [{
    json: {
      ...inputData,
      needs_clarification: true,
      clarification_question: clarificationQuestion,
      is_multi_intent: false,
      item_index: 0,
      total_items: 0
    }
  }];
}

// Return all processed items
return processedItems.map(item => ({ json: item }));

// Preserve upstream payload and attach pending_intent if exists
const base = $('TRF_EnsureOutput').first().json;

const rows = $input.all().map(i => i.json).filter(r => r && r.id);

if (!rows.length) {
  return [{ json: { ...base, pending_intent: null } }];
}

rows.sort((a,b)=> new Date(b.created_at || 0) - new Date(a.created_at || 0));

return [{ json: { ...base, pending_intent: rows[0] } }];

// Merge clarification response with pending intent
// Get the pending intent from the nested path
const inputData = $('TRF_PickLatestPending').first().json;
const pendingIntent = inputData.pending_intent || inputData;
const clarificationResponse = $('TRF_NormalizeAndValidate').first().json;

// Parse the partial intent
let partialIntent;
try {
    partialIntent = typeof pendingIntent.partial_intent === 'string' 
        ? JSON.parse(pendingIntent.partial_intent) 
        : pendingIntent.partial_intent;
} catch (e) {
    partialIntent = pendingIntent.partial_intent || {};
}

// Get current date in America/Belem timezone
const now = new Date();
const belemOffset = -3 * 60; // -03:00 in minutes
const belemTime = new Date(now.getTime() + (belemOffset - now.getTimezoneOffset()) * 60000);
const currentDate = belemTime.toISOString().split('T')[0];

// Parse the clarification response to extract date/time
const responseText = clarificationResponse.text_raw || '';

// Helper function to parse relative dates
function parseDateTime(text, baseDate) {
    const lower = text.toLowerCase().trim();
    const today = new Date(baseDate);

    // Parse time patterns
    const timeMatch = lower.match(/(\d{1,2})(?::(\d{2}))?\s*(?:h|hrs?|horas?)?/i);
    let hours = 9, minutes = 0;
    if (timeMatch) {
        hours = parseInt(timeMatch[1]);
        minutes = timeMatch[2] ? parseInt(timeMatch[2]) : 0;
    }

    // Parse day patterns
    let targetDate = new Date(today);

    if (lower.includes('hoje')) {
        // Today - keep targetDate as is
    } else if (lower.includes('amanhã') || lower.includes('amanha')) {
        targetDate.setDate(targetDate.getDate() + 1);
    } else if (lower.includes('segunda')) {
        const daysUntil = (1 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('terça') || lower.includes('terca')) {
        const daysUntil = (2 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('quarta')) {
        const daysUntil = (3 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('quinta')) {
        const daysUntil = (4 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('sexta')) {
        const daysUntil = (5 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('sábado') || lower.includes('sabado')) {
        const daysUntil = (6 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    } else if (lower.includes('domingo')) {
        const daysUntil = (0 - targetDate.getDay() + 7) % 7 || 7;
        targetDate.setDate(targetDate.getDate() + daysUntil);
    }

    // Set time
    targetDate.setHours(hours, minutes, 0, 0);

    // Format as ISO8601 with -03:00 offset
    const year = targetDate.getFullYear();
    const month = String(targetDate.getMonth() + 1).padStart(2, '0');
    const day = String(targetDate.getDate()).padStart(2, '0');
    const h = String(hours).padStart(2, '0');
    const m = String(minutes).padStart(2, '0');

    return `${year}-${month}-${day}T${h}:${m}:00-03:00`;
}

// Parse the response
const parsedDateTime = parseDateTime(responseText, currentDate);

// Merge intent - INCLUDE owner_phone from pending intent!
const mergedIntent = {
    ...partialIntent,
    owner_phone: pendingIntent.owner_phone,
    type: partialIntent.intent || partialIntent.type || 'task',
    due_at: parsedDateTime,
    notify_at: partialIntent.intent === 'reminder' ? parsedDateTime : null,
    needs_clarification: false,
    clarification_question: null,
    status: 'open',
    pending_intent_id: pendingIntent.id,
    original_message_id: pendingIntent.original_message_id,
    clarification_response: responseText
};

return [{json: mergedIntent}];

