// Guard: only treat message as clarification response if it looks like date/time
const msg = ($('TRF_NormalizeAndValidate').first().json.text_raw || '').toString();
const lower = msg.toLowerCase();

const hasDigit = /\d/.test(lower);
const hasKw = /(hoje|amanh|amanhã|segunda|terca|terça|quarta|quinta|sexta|sabado|sábado|domingo|\b\d{1,2}h\b|\bhs\b|:|às| as )/.test(lower);

// Attach flag to current pending_intent row (the current input item)
return [{
  json: {
    ...$json,
    _clarify_is_valid: (hasDigit || hasKw),
    _clarify_msg_sample: msg.slice(0, 80)
  }
}];

// Check if DB_SaveMessage failed due to unique constraint violation
const input = $input.first();

// Check if there was an error
if (input.error) {
    const errorMsg = input.error.message || '';
    const errorDesc = input.error.description || '';
    const fullError = errorMsg + ' ' + errorDesc;

    // Check for unique constraint violation
    if (fullError.includes('duplicate key') || 
        fullError.includes('unique constraint') ||
        fullError.includes('23505')) {
        // Race condition detected - treat as duplicate
        return [{
            json: {
                ...input.json,
                _race_condition_duplicate: true,
                status: 'duplicate'
            }
        }];
    }

    // Other error - rethrow
    throw new Error('DB_SaveMessage failed: ' + fullError);
}

// No error - continue normally
return [{
    json: {
        ...input.json,
        _race_condition_duplicate: false
    }
}];

// Build query parameters for Supabase
// Try to get hints from Router first
let queryType = 'pending';
let inputData = {};

try {
  const routerData = $('TRF_ParseRouter').first().json;
  queryType = routerData.router?.hints?.query_type || 'pending';
  inputData = routerData;
} catch (e) {
  // Fallback to input
  inputData = $input.first().json;
}

const from_phone = inputData.from_phone;
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1).toISOString();
const tomorrowStart = todayEnd;
const tomorrowEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 2).toISOString();

let filter = '';
switch (queryType) {
    case 'today':
        filter = `owner_phone=eq.${from_phone}&status=eq.open&notify_at=gte.${todayStart}&notify_at=lt.${todayEnd}`;
        break;
    case 'tomorrow':
        filter = `owner_phone=eq.${from_phone}&status=eq.open&notify_at=gte.${tomorrowStart}&notify_at=lt.${tomorrowEnd}`;
        break;
    case 'overdue':
        filter = `owner_phone=eq.${from_phone}&status=eq.open&notify_at=lt.${now.toISOString()}`;
        break;
    default:
        filter = `owner_phone=eq.${from_phone}&status=eq.open`;
}

return [{
    json: {
        ...inputData,
        query_type: queryType,
        filter_string: filter
    }
}];

// Format query response for WhatsApp
// n8n returns each item as separate input, so we use $input.all()
const allItems = $input.all();

// Try to get query_type from Router first, fallback to TRF_BuildQuery
let queryType = 'pending';
let originalData = {};

try {
  const routerData = $('TRF_ParseRouter').first().json;
  queryType = routerData.router?.hints?.query_type || 'pending';
  originalData = routerData;
} catch (e) {
  try {
    const buildQueryData = $('TRF_BuildQuery').first().json;
    queryType = buildQueryData.query_type || 'pending';
    originalData = buildQueryData;
  } catch (e2) {
    // Use defaults
  }
}

// Build header based on query type
let header = '';
switch (queryType) {
    case 'today': header = '📅 *AGENDA DE HOJE*'; break;
    case 'tomorrow': header = '📅 *AGENDA DE AMANHÃ*'; break;
    case 'overdue': header = '⚠️ *ITENS ATRASADOS*'; break;
    default: header = '📋 *PENDÊNCIAS*';
}

// Extract items from n8n format
const items = allItems.map(item => item.json);

if (!items || items.length === 0) {
    return [{
        json: {
            ...originalData,
            response_message: `${header}\n\nNenhum item encontrado! 🎉`
        }
    }];
}

// Format items
const itemLines = items.map((item, i) => {
    const emoji = item.type === 'reminder' ? '🔔' : item.type === 'task' ? '📋' : '📝';
    const title = item.title || 'Sem título';
    let dueStr = '';
    if (item.due_at) {
        const due = new Date(item.due_at);
        dueStr = due.toLocaleString('pt-BR', {
            timeZone: 'America/Belem',
            day: '2-digit',
            month: '2-digit',
            hour: '2-digit',
            minute: '2-digit'
        });
    }
    return `${i + 1}. ${emoji} ${title}${dueStr ? ` (${dueStr})` : ''}`;
}).join('\n');

const footer = items.length >= 5 ? '\n\n_Mostrando top 5. Diga "mais" para ver outros._' : '';

const message = `${header}\n\n${itemLines}${footer}`;

return [{
    json: {
        ...originalData,
        response_message: message
    }
}];

function fmtDateBR(iso) {
  if (!iso) return null;
  const d = new Date(iso);
  return d.toLocaleString('pt-BR', {
    timeZone: 'America/Belem',
    day: '2-digit', month: '2-digit',
    hour: '2-digit', minute: '2-digit'
  });
}

const kind = $json.reply_kind || $json.intent || $json.type;
const title = ($json.reply_title || $json.title || '').trim();
const due = fmtDateBR($json.due_at);
const notify = fmtDateBR($json.notify_at);
const question = $json.clarification_question;

let msg = '';

if (kind === 'clarify') {
  msg = `❓ ${question || 'Preciso de uma data/hora para finalizar.'}`;
} else if (kind === 'task') {
  msg = `✅ Tarefa registrada: *${title || 'Sem título'}*`;
  if (due) msg += `\n📅 Prazo: ${due}`;
} else if (kind === 'reminder') {
  msg = `⏰ Lembrete agendado: *${title || 'Sem título'}*`;
  if (notify) msg += `\n📅 Quando: ${notify}`;
} else if (kind === 'note') {
  msg = `📝 Anotado.`;
  if (title) msg += `\n📌 ${title}`;
} else {
  msg = `✅ Feito.`;
}

// Create item object for DB_CreateItem
const item = {
  owner_phone: $json.from_phone,
  type: kind === 'clarify' ? 'task' : kind,
  title: title || 'Sem título',
  details: $json.details || null,
  status: 'open',
  due_at: $json.due_at || null,
  notify_at: $json.notify_at || null,
  source_message_id: $json.id || null
};

return [{ json: { ...$json, reply_text: msg, item: item } }];

const recent = $input.all().map(i => i.json).filter(x => x.text_raw);

// Try to get original data from TRF_ParseRouter first, fallback to other sources
let originalData = {};
try {
  originalData = $('TRF_ParseRouter').first().json;
} catch (e) {
  try {
    originalData = $('CHK_IsConversational').first().json;
  } catch (e2) {
    originalData = $input.first().json;
  }
}

const nowMsg = originalData.text_raw;

const ctx = recent
  .reverse()
  .map(r => `- (${new Date(r.created_at).toLocaleString('pt-BR', {timeZone:'America/Belem'})}) ${r.text_raw}`)
  .join('\n');

return [{
  json: {
    ...originalData,
    llm_context: ctx || '(sem histórico)',
    llm_current: nowMsg
  }
}];

