// Parse EGA response for conversational (SAFE)
const llmResponse = $input.first().json;
const originalData = $('TRF_ParseCIAResponse').first().json;
let finalText = originalData.cia_response; // fallback to CIA response

try {
  const content = llmResponse.choices?.[0]?.message?.content || "";
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    // Check if approved and final_text exists
    if (parsed.approved === true && parsed.final_text) {
      finalText = parsed.final_text;
    } else if (parsed.approved === false && parsed.final_text) {
      finalText = parsed.final_text;
    }
  }
} catch (e) {
  // Safe: keep fallback
  console.log('EGA parse error, using original:', e.message);
}

return [{
  json: {
    ...originalData,
    final_response: finalText
  }
}];

// Build context for CIA from recent messages
const messages = $input.all().map(item => item.json);

// Format recent messages as context
let context = '';
if (messages.length > 0) {
  context = messages.slice(0, 3).reverse().map(m => {
    const dir = m.direction === 'in' ? 'Usuário' : 'Assistente';
    const text = m.text_raw || m.extracted_text || '[mídia]';
    return `${dir}: ${text}`;
  }).join('\n');
}

return [{
