try {
  const fetchResult = $input.all();
  if (fetchResult && fetchResult.length > 0) {
    // Supabase returns array of items
    messages = fetchResult.map(item => item.json);
  }
} catch (e) {
  // No messages found
}

// Get recent messages (up to 3 in/out pairs)
let contextLines = [];
if (Array.isArray(messages) && messages.length > 0) {
  const sorted = messages.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
  const recent = sorted.slice(0, 6);
  for (const msg of recent.reverse()) {
    const dir = msg.direction === 'in' ? 'USER' : 'EMII';
    const text = (msg.text_raw || '').substring(0, 100);
    if (text) {
      contextLines.push(`${dir}: ${text}`);
    }
  }
}

const recent_context = contextLines.length > 0 
  ? contextLines.join('\n') 
  : '(sem histórico recente)';

return [{
  json: {
    ...inputData,
    recent_context,
    text_raw: inputData.text_raw || ''
  }
}];

