// Parse Router LLM response
const inputData = $('TRF_BuildRouterContext').first().json;
const llmResponse = $input.first().json;

let route = 'fallback';
let confidence = 0;
let reason = 'parse_error';
let hints = { query_type: null, is_multi: false, pref_change: false };

try {
  // Extract content from LLM response
  let content = '';
  if (llmResponse.choices && llmResponse.choices[0]) {
    content = llmResponse.choices[0].message?.content || '';
  }

  // Clean markdown if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse JSON
  const parsed = JSON.parse(content);

  // Validate required fields
  if (parsed.route && ['conversational', 'query', 'knowledge', 'config', 'capture'].includes(parsed.route)) {
    route = parsed.route;
    confidence = typeof parsed.confidence === 'number' ? parsed.confidence : 85;
    reason = parsed.reason || 'LLM decision';

    if (parsed.hints) {
      hints.query_type = parsed.hints.query_type || null;
      hints.is_multi = parsed.hints.is_multi === true;
      hints.pref_change = parsed.hints.pref_change === true;
    }
  }
} catch (e) {
  // Keep fallback values
  reason = 'json_parse_error: ' + e.message;
}

return [{
  json: {
    ...inputData,
    router: {
      route,
      confidence,
      reason,
      hints,
      use_fallback: route === 'fallback' || confidence < 70
    }
  }
}];

