  }

  // Clean markdown if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  const parsed = JSON.parse(content);
  preference_key = parsed.preference_key;
  preference_value = parsed.preference_value;
  confirmation_message = parsed.confirmation_message || 'Preferência atualizada!';

  // Convert to seconds if needed (the table uses lead_time_default_seconds)
  if (preference_key === 'reminder_lead_time' && typeof preference_value === 'number') {
    // Value is already in seconds from LLM
  }
} catch (e) {
  confirmation_message = 'Erro ao processar preferência: ' + e.message;
}

return [{
  json: {
    ...inputData,
    preference_key,
    preference_value,
    confirmation_message,
    has_valid_pref: preference_key !== null && preference_value !== null
  }
}];

// Prepare payload for WF04
const allItems = $input.all();
const firstItem = allItems[0].json;

// Extract items array from LLM response
const items = allItems.map(item => ({
  type: item.json.intent || 'task',
  title: item.json.title || 'Sem título',
  details: item.json.details || null,
  due_at: item.json.due_at || null
}));

return [{
  json: {
    owner_phone: firstItem.from_phone,
    source_message_id: firstItem.id,
    items: items,
    lead_time_default_seconds: firstItem.lead_time_default_seconds || 900
  }
}];

// Format final response with summary
const wf04Result = $input.first().json;
const originalData = $('TRF_ParseIntent').first().json;

return [{
  json: {
    ...originalData,
    reply_text: wf04Result.summary_text || '✅ Itens processados.',
    created_count: wf04Result.created_count || 0
  }
}];

// Start execution timer
